    val checkedValue = getCompositionLocalRadioGroupCheckedValue()
    val radioGroupName = getCompositionLocalRadioGroupName()

    Input(
        type = InputType.Radio,
        attrs = {
            attrs?.invoke(this)
            if (id != null) id(id)
